--allow-headers strings cors allow headers (env: GRAPHIK_ALLOW_HEADERS) (default [*]) --allow-methods strings cors allow methods (env: GRAPHIK_ALLOW_METHODS) (default [HEAD,GET,POST,PUT,PATCH,DELETE]) --allow-origins strings cors allow origins (env: GRAPHIK_ALLOW_ORIGINS) (default [*]) --metrics enable prometheus &amp; pprof metrics (emv: GRAPHIK_METRICS = true) (default true) --open-id string open id connect discovery uri ex: https://accounts.google.com/.well-known/openid-configuration (env: GRAPHIK_OPEN_ID) --playground-client-id string playground oauth client id (env: GRAPHIK_PLAYGROUND_CLIENT_ID) --playground-client-secret string playground oauth client secret (env: GRAPHIK_PLAYGROUND_CLIENT_SECRET --playground-redirect string playground oauth redirect (env: GRAPHIK_PLAYGROUND_REDIRECT) (default &#34;http://localhost:7820/playground/callback&#34;) --root-users strings a list of email addresses that bypass registered authorizers(env: GRAPHIK_ROOT_USERS) --storage string persistant storage path (env: GRAPHIK_STORAGE_PATH) (default &#34;/tmp/graphik&#34;) --tls-cert string path to tls certificate (env: GRAPHIK_TLS_CERT) --tls-key string path to tls key (env: GRAPHIK_TLS_KEY)
       message  Ref {  // gtype is the type of the doc/connection ex: pet  string  gtype = 1 [(validator.field) = {regex : &#34;^.{1,225}$&#34;}];  // gid is the unique id of the doc/connection within the context of it&#39;s type  string  gid = 2 [(validator.field) = {regex : &#34;^.{1,225}$&#34;}];}
  message  Doc {  // ref is the ref to the doc  Ref  ref = 1 [(validator.field) = {msg_exists : true}];  // k/v pairs  google.protobuf.Struct  attributes = 2;}
